class Solution:
    def maximumSumSubsequence(self, nums, queries):
        MOD = 10**9 + 7
        def max_non_adj(arr):
            if not arr:
                return 0
            prev2, prev1 = 0, 0
            for x in arr:
                prev2, prev1 = prev1, max(prev1, prev2 + x)
            return prev1
        total = 0
        n = len(nums)
        arr = nums[:]
        for pos, xi in queries:
            arr[pos] = xi
            total = (total + max(0, max_non_adj(arr))) % MOD
        return total

