var maximumSumSubsequence = function(nums, queries) {
    const MOD = BigInt(10**9 + 7);
    const n = nums.length;
    let size = 1;
    while (size < n) size <<= 1;
    // tree[i] = [f00, f01, f10, f11]
    const tree = Array.from({length: 2*size}, () => [0,0,0,0]);

    function makeLeaf(v) {
        const val = Math.max(0, v);
        return [0, 0, 0, val];
    }

    function merge(L, R) {
        const [l00,l01,l10,l11] = L;
        const [r00,r01,r10,r11] = R;
        function best(la, rb) {
            const lv  = la === 0 ? l00 : l10;
            const lv1 = la === 0 ? l01 : l11;
            const rv0 = rb === 0 ? r00 : r01;
            const rv1 = rb === 0 ? r10 : r11;
            return Math.max(lv + rv0, lv + rv1, lv1 + rv0);
        }
        return [best(0,0), best(0,1), best(1,0), best(1,1)];
    }

    function build(i) {
        if (i >= size) return;
        build(2*i); build(2*i+1);
        tree[i] = merge(tree[2*i], tree[2*i+1]);
    }

    for (let i = 0; i < n; i++) tree[size+i] = makeLeaf(nums[i]);
    build(1);

    function update(pos, val) {
        let i = size + pos;
        tree[i] = makeLeaf(val);
        i >>= 1;
        while (i >= 1) {
            tree[i] = merge(tree[2*i], tree[2*i+1]);
            i >>= 1;
        }
    }

    let total = BigInt(0);
    const MOD_N = 10**9 + 7;
    for (const [pos, xi] of queries) {
        update(pos, xi);
        total = (total + BigInt(tree[1][3])) % MOD;
    }
    return Number(total);
};
